import { registerMvuSchema } from 'https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js';

export const Schema = z.object({
  学园日程: z.object({
    当前天数: z.coerce.number().prefault(1),
    当前时间段: z.string().prefault('早晨'),
    今日剩余行动力: z.coerce.number().transform(v => Math.max(0, v)).prefault(3),
    当前位置: z.string().prefault('哥哥的房间')
  }),

  恋爱日常: z.object({
    当前包容度: z.coerce.number().transform(v => _.clamp(v, 0, 9999)).prefault(1000),
    醋意爆发指数: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
    端水疲劳度: z.coerce.number().transform(v => Math.max(1, v)).prefault(1)
  }),

  端水大师口袋: z.object({
    存读档次数: z.coerce.number().prefault(1),
    礼物栏: z.record(
      z.string().describe('礼物名称'),
      z.object({
        数量: z.coerce.number().prefault(1),
        描述: z.string().prefault('')
      })
    ).prefault({})
  }),

  心动名单: z.record(
    z.string().describe('女孩姓名'),
    z.object({
      依赖度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
      当前心情: z.string().prefault('未观测'),
      当前出没地: z.string().prefault('未知'),
      心动开关: z.array(z.string()).prefault([]),
      是否告白成功: z.boolean().prefault(false)
    })
  )
});

$(() => {
  registerMvuSchema(Schema);
})

