    const apSpan = document.getElementById('disp-ap');
    if (apSpan && parseInt(apSpan.innerText) <= 0 && !option.includes('{{user}}的房间')) {
      alert("今天的行动力已经耗尽啦，{{user}}该回房间休息，或者进入下一个时间段了哦！");
      return;
    }

    const cmd = `/send ${option} | /trigger`;

    if(typeof triggerSlash === 'function') {
      triggerSlash(cmd);
    } else {
      const ta = parent.document.getElementById('send_textarea') || document.getElementById('send_textarea');
      if(ta) {
        ta.value = option;
        ta.dispatchEvent(new Event('input', {bubbles:true}));
        (parent.document.getElementById('send_but') || document.getElementById('send_but'))?.click();
      }
    }
  };
</script>

