    .tab-btn {
      flex: 1; padding: 12px 0; background: transparent; border: none;
      color: var(--text-dim); font-family: 'Noto Serif SC', serif; font-size: 11px;
      cursor: pointer; transition: all 0.3s ease; display: flex; flex-direction: column; align-items: center; gap: 4px;
    }
    .tab-btn i { font-size: 14px; }
    .tab-btn:hover { color: var(--text-main); background: hsla(340, 60%, 60%, 0.1); }
    .tab-btn.active { color: var(--pl-pink); background: hsla(340, 60%, 60%, 0.15); }
    .tab-btn.active::after {
      content: ''; position: absolute; bottom: 0; width: 30%; height: 2px;
      background: var(--pl-pink); border-radius: 2px 2px 0 0; box-shadow: 0 -1px 3px var(--pl-pink);
    }

    /* --- 内容区 --- */
    .tab-content { position: relative; z-index: 1; display: none; padding: 15px; animation: fadeIn 0.3s ease; max-height: 400px; overflow-y: auto; }
    .tab-content.active { display: block; }
    .tab-content::-webkit-scrollbar { width: 4px; }
    .tab-content::-webkit-scrollbar-thumb { background: hsla(340, 50%, 60%, 0.5); border-radius: 2px; }
    @keyframes fadeIn { from { opacity: 0; transform: translateY(5px); } to { opacity: 1; transform: translateY(0); } }

    .section-title {
      font-size: 12px; font-weight: bold; color: var(--pl-blue); margin-bottom: 10px;
      padding-bottom: 4px; border-bottom: 1px dashed hsla(350, 60%, 60%, 0.3);
      display: flex; align-items: center; gap: 6px;
    }

    /* --- 网格与卡片 --- */
    .grid-2 { display: grid; grid-template-columns: repeat(2, 1fr); gap: 8px; margin-bottom: 12px; }
    .grid-3 { display: grid; grid-template-columns: repeat(3, 1fr); gap: 8px; margin-bottom: 12px; }

    .info-card {
      background: hsla(345, 20%, 20%, 0.7); border: 1px solid hsla(340, 40%, 40%, 0.3);
      border-radius: 8px; padding: 10px; transition: 0.2s;
    }
    .info-card:hover { border-color: var(--pl-pink-dark); background: hsla(345, 20%, 25%, 0.8); }
    .info-label { font-size: 10px; color: var(--text-dim); margin-bottom: 4px; display: flex; align-items: center; gap: 4px; }
    .info-val { font-size: 14px; font-weight: bold; color: var(--text-main); }
    .val-pink { color: var(--pl-pink); }
    .val-blue { color: var(--pl-blue); }

    /* --- 进度条 --- */
    .bar-box { margin-top: 6px; }
    .bar-bg { height: 6px; background: hsla(0, 0%, 10%, 0.5); border-radius: 3px; overflow: hidden; }
    .bar-fill { height: 100%; border-radius: 3px; transition: width 0.5s ease; }
    .fill-blue { background: linear-gradient(90deg, var(--pl-blue-dark), var(--pl-blue)); box-shadow: 0 0 5px var(--pl-blue-dark); }
    .fill-pink { background: linear-gradient(90deg, var(--pl-pink-dark), var(--pl-pink)); box-shadow: 0 0 5px var(--pl-pink-dark); }

    /* --- 女孩列表 --- */
    .girl-item {
      display: flex; align-items: center; gap: 10px; padding: 10px;
      background: hsla(345, 20%, 20%, 0.6); border: 1px solid hsla(340, 40%, 40%, 0.3);
      border-radius: 8px; margin-bottom: 8px; transition: 0.2s;
    }
    .girl-item:hover { transform: translateX(2px); border-color: var(--pl-pink); }
    .girl-avatar {
      width: 32px; height: 32px; border-radius: 50%; background: hsla(340, 50%, 40%, 0.5);
      display: flex; align-items: center; justify-content: center; font-weight: bold; color: var(--pl-pink); border: 1px solid var(--pl-pink-dark);
    }
    .girl-info { flex: 1; }
    .girl-name-row { display: flex; justify-content: space-between; align-items: baseline; margin-bottom: 2px; }
    .girl-name { font-size: 12px; font-weight: bold; color: var(--text-main); }
    .girl-loc { font-size: 9px; color: var(--gold-light); background: hsla(30, 50%, 30%, 0.5); padding: 2px 6px; border-radius: 10px; border: 1px solid hsla(30, 60%, 40%, 0.3); }
    .girl-mood { font-size: 10px; color: var(--text-dim); margin-bottom: 4px; }

    /* --- 物品栏 --- */
    .item-slot { text-align: center; padding: 10px 5px; background: hsla(345, 20%, 20%, 0.6); border: 1px solid hsla(340, 40%, 40%, 0.3); border-radius: 6px; position: relative; }
    .item-icon { font-size: 20px; margin-bottom: 5px; color: var(--gold-light); }
    .item-name { font-size: 10px; color: var(--text-main); }
    .item-count { position: absolute; top: 3px; right: 3px; font-size: 9px; background: var(--pl-pink-dark); color: #fff; padding: 1px 5px; border-radius: 4px; }

    /* --- 底部快捷操作 --- */
    .quick-actions {
      position: relative; z-index: 2; padding: 12px 15px; background: hsla(345, 20%, 15%, 0.95);
      border-top: 1px solid hsla(340, 60%, 50%, 0.3); box-shadow: 0 -4px 10px var(--shadow-color);
    }
    .quick-grid { display: flex; gap: 8px; justify-content: space-between; }
    .quick-btn {
      flex: 1; display: flex; flex-direction: column; align-items: center; gap: 5px;
      padding: 10px 0; background: hsla(345, 30%, 25%, 0.5); border: 1px solid hsla(340, 50%, 40%, 0.5);
      border-radius: 8px; cursor: pointer; transition: 0.2s; color: var(--text-dim); position: relative;
