    .quick-btn.rest i { color: var(--pl-blue); }
    .quick-btn.explore i { color: var(--pl-pink); }
    .quick-btn span { font-size: 10px; font-weight: bold; }

    /* 下拉菜单 */
    .dropdown { position: relative; flex: 1.5; }
    .dropdown-menu {
      display: none; position: absolute; bottom: calc(100% + 10px); left: 50%; transform: translateX(-50%);
      background: hsla(345, 25%, 15%, 0.98); border: 1px solid var(--pl-pink-dark); border-radius: 8px;
      padding: 8px; min-width: 140px; box-shadow: 0 4px 20px var(--shadow-color); z-index: 100;
    }
    .dropdown-menu.show { display: grid; grid-template-columns: 1fr 1fr; gap: 5px; animation: slideUp 0.2s ease; }
    @keyframes slideUp { from { opacity: 0; transform: translateX(-50%) translateY(10px); } to { opacity: 1; transform: translateX(-50%) translateY(0); } }

    .loc-option {
