    /* Toast 提示 */
    .toast {
      position: absolute; top: 20px; left: 50%; transform: translateX(-50%);
      background: hsla(350, 60%, 50%, 0.9); color: #fff; padding: 8px 15px; border-radius: 20px;
      font-size: 11px; z-index: 1000; opacity: 0; transition: 0.3s; pointer-events: none; border: 1px solid var(--pl-pink-light);
    }
    .toast.show { opacity: 1; transform: translateX(-50%) translateY(10px); }
  </style>

  <script>
    // === 交互函数提取到全局作用域 ===

    // 切换 Tab 页
    window.switchTab = function(targetId, btnElement) {
      // 移除所有按钮的 active 类
      document.querySelectorAll('.tab-btn').forEach(b => b.classList.remove('active'));
      // 给当前点击的按钮添加 active 类
      btnElement.classList.add('active');

      // 隐藏所有内容区域
      document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));
      // 显示目标内容区域
      document.getElementById(targetId).classList.add('active');
    };

    // 发送指令核心逻辑
    window.execCmd = function(msg) {
      if (typeof triggerSlash === 'function') {
        triggerSlash(`/send ${msg} | /trigger`);
        showToast("正在前往：" + msg);
      } else {
        const ta = parent.document.getElementById('send_textarea');
        if (ta) {
          ta.value = msg;
          ta.dispatchEvent(new Event('input', {bubbles:true}));
          const btn = parent.document.getElementById('send_but');
          if (btn) btn.click();
          showToast("指令已发送");
        } else {
          showToast("错误：未找到发送框");
        }
      }
      document.getElementById('explore-menu')?.classList.remove('show');
    };

    window.showToast = function(msg) {
      const toast = document.getElementById('toast-msg');
      if(toast) {
        toast.textContent = msg;
        toast.classList.add('show');
        setTimeout(() => toast.classList.remove('show'), 2000);
      }
    };

    // 快捷按钮操作
    window.gotoLocation = function(loc) { execCmd("前往 " + loc); };
    window.openShop = function() { execCmd("打开商城"); };
    window.restTime = function() { execCmd("休息推进时间"); };
    window.toggleExplore = function() {
      document.getElementById('explore-menu').classList.toggle('show');
    };

    // 音乐播放控制
    window.toggleMusic = function() {
      const audio = document.getElementById('bgm-audio');
      const toggleBtn = document.getElementById('bgm-toggle');
      const waves = document.getElementById('bgm-waves');
      const statusText = document.getElementById('bgm-status');

      audio.volume = 0.4; // 设置音量

      if (audio.paused) {
        audio.play().then(() => {
          toggleBtn.innerHTML = '<i class="fas fa-pause"></i>';
          waves.classList.add('playing');
          statusText.textContent = 'PLAYING';
          statusText.style.color = 'var(--pl-pink)';
          document.querySelectorAll('.wave').forEach(w => w.style.background = 'var(--pl-pink)');
        }).catch(e => {
          console.error("播放失败:", e);
          showToast("播放失败，请先点击界面任意位置后再试");
        });
      } else {
        audio.pause();
        toggleBtn.innerHTML = '<i class="fas fa-play"></i>';
        waves.classList.remove('playing');
        statusText.textContent = 'READY';
        statusText.style.color = 'var(--pl-blue)';
        document.querySelectorAll('.wave').forEach(w => w.style.background = 'var(--pl-blue)');
      }
    };

    // 点击外部关闭菜单
    document.addEventListener('click', function(e) {
      if (!e.target.closest('.dropdown')) {
        document.getElementById('explore-menu')?.classList.remove('show');
      }
    });
  </script>

  <!-- 数据加载逻辑仍使用 module 以便调用库函数 -->
  <script type="module">
    function populateCharacterData() {
      if (typeof getAllVariables !== 'function' || typeof _ === 'undefined') return;
      const vars = getAllVariables();

      try {
        const daily = _.get(vars, 'stat_data.学园日程', {});
        $('#val-day').text('第 ' + (daily['当前天数'] || 1) + ' 天');
        $('#val-time').text(daily['当前时间段'] || '早晨');
        $('#val-ap').text(daily['今日剩余行动力'] || 0);
        $('#ui-location').text(daily['当前位置'] || '未知地点');

        const combat = _.get(vars, 'stat_data.恋爱日常', {});
        const tol = parseInt(combat['当前包容度']) || 0;
        const jel = parseInt(combat['醋意爆发指数']) || 0;

        $('#val-tol').text(tol);
        $('#bar-tol').css('width', Math.min(100, (tol/9999)*100) + '%');
        $('#val-jel').text(jel);
        $('#bar-jel').css('width', Math.min(100, jel) + '%');
        $('#val-fat').text(combat['端水疲劳度'] || 1);

        const girls = _.get(vars, 'stat_data.心动名单', {});
        let girlHtml = '';
        Object.entries(girls).forEach(([name, data]) => {
          if(data['依赖度'] > 0 || data['当前出没地'] !== '未知') {
            const dep = data['依赖度'] || 0;
            const heart = data['是否告白成功'] ? '💝 ' : '';
            girlHtml += `
              <div class="girl-item">
                <div class="girl-avatar">${name.charAt(0)}</div>
                <div class="girl-info">
                  <div class="girl-name-row">
                    <span class="girl-name">${heart}${name}</span>
                    <span class="girl-loc"><i class="fas fa-map-marker-alt"></i> ${data['当前出没地'] || '未知'}</span>
                  </div>
                  <div class="girl-mood">${data['当前心情'] || '平静'}</div>
                  <div class="bar-bg" style="height:4px"><div class="bar-fill fill-pink" style="width:${Math.min(100, dep)}%"></div></div>
                </div>
              </div>
            `;
          }
        });
        if(!girlHtml) girlHtml = '<div style="text-align:center; color:#888; padding:20px; font-size:12px;">暂无遭遇信息...</div>';
        $('#girls-list').html(girlHtml);

        const pocket = _.get(vars, 'stat_data.端水大师口袋', {});
        $('#val-save').text(pocket['存读档次数'] || 0);

        const gifts = _.get(pocket, '礼物栏', {});
        let itemHtml = '';
        Object.entries(gifts).forEach(([gName, gData]) => {
          const num = gData['数量'] || 0;
          if(num > 0) {
            itemHtml += `
              <div class="item-slot">
                <div class="item-count">${num}</div>
                <div class="item-icon"><i class="fas fa-gift"></i></div>
                <div class="item-name">${gName}</div>
              </div>
            `;
          }
        });
        if(!itemHtml) itemHtml = '<div style="grid-column:1/-1; text-align:center; color:#888; padding:20px; font-size:12px;">口袋空空如也</div>';
        $('#items-grid').html(itemHtml);

      } catch (e) {
        console.error("解析终端变量失败:", e);
      }
    }

    async function init() {
      if (typeof waitGlobalInitialized === 'function') {
        await waitGlobalInitialized('Mvu');
        populateCharacterData();
        if (typeof eventOn === 'function' && typeof Mvu !== 'undefined') {
          eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, () => {
            populateCharacterData();
          });
        }
      }
    }

    if (typeof errorCatched === 'function' && typeof $ !== 'undefined') {
      $(errorCatched(init));
    }
  </script>
</head>
