<style>
    :root {
        /* === 黑市商城配色 (樱花深色系) === */
        --pl-blue: hsl(350, 70%, 80%);     /* 樱花白/淡粉 (用于价格、次要文字) */
        --pl-pink: hsl(340, 80%, 75%);     /* 主题樱花粉 (用于高亮、图标) */
        --pl-pink-dark: hsl(340, 70%, 60%);/* 深粉 (用于边框、危险警示) */

