        --bg-dark: hsl(345, 20%, 20%);     /* 卡片底色 */

        --ivory: hsl(0, 0%, 98%);          /* 主文字色 */
        --ivory-dim: hsl(345, 15%, 80%);   /* 暗文字色 */
