    }

    /* 容器 */
    .tow-combat-container {
        font-family: 'Noto Serif SC', serif;
        background: linear-gradient(135deg, var(--bg-deep) 0%, var(--bg-dark) 100%);
        padding: 15px;
        position: relative;
        width: 100%;
        box-sizing: border-box;
        border: 1px solid hsla(340, 60%, 50%, 0.3);
        border-radius: 8px;
