<div class="tarot-container">
    <div class="tarot-header">
        <i class="fas fa-envelope-open-heart"></i> 命运选项 <i class="fas fa-envelope-open-heart"></i>
    </div>
    <div class="card-deck" id="card-deck"></div>
    <div class="custom-input-area">
        <input type="text" class="custom-input" id="custom-action-input" placeholder="输入你想做的事，或者试着摸摸她的头...">
        <button class="custom-btn" id="custom-action-send">回应</button>
