<script>
(function() {
    // 1. 获取原始内容 (处理HTML转义)
    const tempDiv = document.createElement('div');
    tempDiv.innerHTML = `$1`;
    // 将 <br> 替换为换行符，以便按行分割
    const rawHTML = tempDiv.innerHTML;
    const textWithBreaks = rawHTML.replace(/<br\s*\/?>/gi, '\n').replace(/<\/div>/gi, '\n');
    tempDiv.innerHTML = textWithBreaks;
    let rawData = tempDiv.innerText || tempDiv.textContent;

    const hasTriggerSlash = typeof triggerSlash === 'function';
    const container = document.getElementById('card-deck');

    // 2. 类型配置 (适配纯爱机制深色版)
    const typeConfig = {
        '理智': { class: 'card-blue', icon: 'fa-brain', label: '理智牌' },
        '倾听': { class: 'card-pink', icon: 'fa-ear-listen', label: '倾听牌' },
        '宠溺': { class: 'card-red', icon: 'fa-hand-holding-heart', label: '宠溺牌' },
        '作死': { class: 'card-dark', icon: 'fa-skull-crossbones', label: '雷区牌' },
        '商城': { class: 'card-gold', icon: 'fa-gift', label: '小卖部' }
    };
    const defaultConfig = { class: 'card-blue', icon: 'fa-comment-dots', label: '回应牌' };

    // 3. 解析逻辑 (按行分割 + 括号提取)
    const lines = rawData.split('\n').filter(line => line.trim());
    container.innerHTML = '';

    let cardCount = 0;

    lines.forEach(line => {
        line = line.trim();
        const firstBracket = line.indexOf('[');
        const lastBracket = line.lastIndexOf(']');

        if (firstBracket !== -1 && lastBracket > firstBracket) {
            const contentRaw = line.substring(firstBracket + 1, lastBracket);
            const parts = contentRaw.split('|');

            if (parts.length >= 2) {
                const tag = parts[0].trim();
                let cost, content;

                if (parts.length >= 3) {
                    cost = parts[1].trim();
                    content = parts.slice(2).join('|').trim();
                } else {
                    cost = "无消耗";
                    content = parts[1].trim();
                }

                const config = typeConfig[tag] || defaultConfig;
                const card = document.createElement('div');
                card.className = `fate-card ${config.class}`;
                card.innerHTML = `
                    <div class="card-type">${config.label}</div>
                    <div class="card-body">
                        <i class="fas ${config.icon} card-icon"></i>
                        <div class="card-desc">${content}</div>
                    </div>
                    <div class="card-cost">${cost}</div>
                `;

                // 点击指令
                let command = content;
                if (tag === '商城' && !content.startsWith('/')) command = '打开商城';
                const finalCmd = command.startsWith('/') ? command : `/send ${command} | /trigger`;

                card.addEventListener('click', function() {
                    if (hasTriggerSlash) {
                        this.style.transform = 'scale(0.95)';
                        this.style.opacity = '0.8';
                        setTimeout(() => triggerSlash(finalCmd), 150);
                    }
                });

                container.appendChild(card);
                cardCount++;
            }
        }
    });

    if (cardCount === 0) {
        container.innerHTML = '<div style="color: var(--text-dim); padding:20px;">命运在等待你的选择...</div>';
    }

    // 4. 输入框
    const customInput = document.getElementById('custom-action-input');
    const customSendBtn = document.getElementById('custom-action-send');
    function sendCustomAction() {
        const action = customInput.value.trim();
        if (action && hasTriggerSlash) {
            triggerSlash('/send ' + action + ' | /trigger');
            customInput.value = '';
        }
    }
    customSendBtn.addEventListener('click', sendCustomAction);
    customInput.addEventListener('keypress', function(e) { if (e.key === 'Enter') sendCustomAction(); });

})();
</script>
</body>
